#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 网文写作.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="网文写作"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 平台与频道定位
  9.2 流派套路与红利窗口
  9.3 金手指与爽点引擎设计
  9.4 力量体系/世界观自洽性
  9.5 数据诊断与救书
  9.6 变现与可改编性
  9.7 合规与 AI 政策

背后的心智模型:
  • 黄金三章定生死：为留人而非为铺垫写开局: 网文开局不是慢热铺垫，是前三章/万字内必须抛出金手指 + 制造冲突 + 埋钩子 + 建立代入，否则签约率与追读直接塌——「最惨/最爽不过三章」。
  • 爽点是可理性设计的工程对象，不是灵感: 愤怒的香蕉「一开始是欲望，到后来是情绪，最后变成需求」——爽点能被作者主动观察、拆解、设计，心理描写可把爽感挖到极致，而非等灵感降临。
  • 先世界观后升级：让爽感从规则里长出来: 爱潜水的乌贼「我先做世界观，再考虑怎么升级，再考虑升级的表现」——力量体系要自洽，所有人守同一规则、只给主角破规则的方式，前文每个字都约束结局。

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "平台与频道定位"
  "流派套路与红利窗口"
  "金手指与爽点引擎设计"
  "力量体系/世界观自洽性"
  "数据诊断与救书"
  "变现与可改编性"
  "合规与 AI 政策"
)
declare -a DIM_QUESTIONS=(
  "目标平台的商业模式（付费均订 vs 免费完读率/广告分成）、读者画像、男频/女频频道与具体类型的匹配度。"
  "当前哪些流派/套路在涨、是否已过热同质化、自己擅长的方向有没有红利。"
  "金手指是否独有/稀缺/功能明确、爽点从读者哪个欲望出发、前三章爽点序列。"
  "设定逻辑是否自洽、是否够推导后续升级、规则边界是否清晰（谁能破规则、代价是什么）。"
  "追读率/完读率/均订/章评的掉点位置，定位「哪一章/哪个情节让读者弃书」。"
  "题材是否可改编（短剧/影视/动漫）、数据是否达 IP 评估阈值、写作时是否留了改编空间。"
  "敏感词/内容审核红线、AI 辅助 vs 代写的平台政策、签约合同条款（买断 vs 分成/版权归属/霸王条款）。"
)
declare -a DIM_SOURCES=(
  "起点/番茄/晋江的畅销榜与作家后台、各平台读者评论区与作家专区说明。"
  "月票榜/畅销榜的流派趋势变化、龙空（lkong）原创讨论区的题材热度、年度《网络文学发展报告》。"
  "同题材爆款的开局拆解、愤怒的香蕉「欲望→情绪→需求」框架、平台编辑对开篇节奏的反馈。"
  "自建设定卡 + 同类世界观流标杆作（如《诡秘之主》序列推导）、墨者/壹写作设定管理。"
  "平台作家后台数据中心的追读/完读曲线与章评（本环节核心，比码字软件重要）。"
  "平台 IP 池与短剧榜、番茄短故事赛道、头部 IP 改编案例（如短故事→短剧周期）。"
  "平台官方公告与作家专区规则、司法部普法（融梗/抄袭界定）、2025-09 生效的 AI 生成内容标识办法。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "一句话给出「推荐平台 + 频道 + 题材类型 + 对应的开局节奏基调（慢半拍 vs 第一章爆点）」。"
  "选定流派 + 一个差异化切入点（避免红海正面硬刚），标注红利窗口的时效风险。"
  "金手指设定（能力 + 稀缺性 + 持续产爽机制）+ 黄金三章的爽点/钩子序列清单。"
  "力量体系骨架（等级/规则/升级路径）+ 主角破规则的方式 + 自洽性风险点。"
  "扑点判断（结构性 vs 噪音）+ 救书三招（改大纲/换爽点/加节奏）或止损（完本投新书）决策。"
  "改编路径建议（短剧/长线影视/动漫）+ 写作时应保留的可改编爽点节奏与人设稳定性。"
  "合规清单（过审要点 + AI 使用边界 + 签约前必查条款），标注政策时效风险（Decay risk: high）。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
